import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Alert {
  title: string;
  timestamp: string;
}

interface AlertCategory {
  category: string;
  unreadCount: number;
  alerts: Alert[];
}

interface WidgetData {
  alerts: AlertCategory[];
}

export default function Widget() {
  const data = response.data as WidgetData;
  const meta = response.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 450,
        bgcolor: '#1E1E1E',
        color: '#FFFFFF',
        borderRadius: 2,
      }}
      elevation={3}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: meta.primaryColor }}>
            Notifications Center
          </Typography>
          <Stack spacing={1}>
            {data.alerts.slice(0, 3).map((categoryData) => (
              <Box key={categoryData.category}>
                <Typography variant="body1" sx={{ fontWeight: 500, mb: 0.5 }}>
                  {categoryData.category} ({categoryData.unreadCount})
                </Typography>
                <Stack spacing={0.5}>
                  {categoryData.alerts.map((alert, index) => (
                    <Box key={index}>
                      <Typography variant="body2" sx={{ color: '#B0B0B0' }}>
                        {alert.title}
                      </Typography>
                      <Typography variant="caption" sx={{ color: '#8D8D8D' }}>
                        {new Date(alert.timestamp).toLocaleString()}
                      </Typography>
                    </Box>
                  ))}
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
